from flask import Flask, send_from_directory

app = Flask(__name__)

@app.route('/static/<path:filename>')
def legacy_static(filename):
    # Check if the file exists in the uploads directory
    try:
        return send_from_directory('uploads', filename)
    except FileNotFoundError:
        # Attempt to serve the file with a different naming convention
        # Example: if the file is not found, try appending '_old' to the filename
        new_filename = f"{filename}_old"
        return send_from_directory('uploads', new_filename)

if __name__ == '__main__':
    app.run(debug=True)